type Rating = {
    mu: number;
    sigma: number;
};
type Team = Rating[];
type Teams = readonly (readonly Rating[])[];
type RateTeam<U extends readonly Rating[]> = {
    -readonly [J in keyof U]: Rating;
};
type RateResult<T extends Teams> = {
    -readonly [K in keyof T]: RateTeam<T[K]>;
};
type Rank = number;
type Gamma = (c: number, k: number, mu: number, sigmaSq: number, team: Rating[], qRank: number) => number;
type Model = (teams: Team[], options?: Options) => Team[];
type Options = {
    z?: number;
    mu?: number;
    sigma?: number;
    epsilon?: number;
    gamma?: Gamma;
    beta?: number;
    model?: Model;
    rank?: Rank[];
    score?: number[];
    weight?: number[][];
    tau?: number;
    margin?: number;
    alpha?: number;
    target?: number;
    limitSigma?: boolean;
    balance?: boolean;
    kappa?: number;
};

export type { Gamma, Model, Options, Rank, RateResult, RateTeam, Rating, Team, Teams };
